{"meta": null, "content": [{"type": "text", "text": "{"content":"100: \n101: StreamEncoderImpl::StreamEncoderImpl(ConnectionImpl\u0026 connection,\n102:                                      StreamInfo::BytesMeterSharedPtr\u0026\u0026 bytes_meter)\n103:     : connection_(connection), disable_chunk_encoding_(false), chunk_encoding_(true),\n104:       connect_request_(false), is_tcp_tunneling_(false), is_response_to_head_request_(false),\n105:       is_response_to_connect_request_(false), bytes_meter_(std::move(bytes_meter)) {\n106:   if (!bytes_meter_) {\n107:     bytes_meter_ = std::make_shared\u003cStreamInfo::BytesMeter\u003e();\n108:   }\n109:   if (connection_.connection().aboveHighWatermark()) {\n110:     runHighWatermarkCallbacks();\n111:   }\n112: }\n113: \n114: void StreamEncoderImpl::encodeHeader(absl::string_view key, absl::string_view value) {\n115:   ASSERT(!key.empty());\n116: \n117:   const uint64_t header_size = connection_.buffer().addFragments({key, COLON_SPACE, value, CRLF});\n118: \n119:   bytes_meter_-\u003eaddHeaderBytesSent(header_size);\n120: }\n121: \n122: void StreamEncoderImpl::encodeFormattedHeader(absl::string_view key, absl::string_view value,\n123:                                               HeaderKeyFormatterOptConstRef formatter) {\n124:   if (formatter.has_value()) {\n125:     encodeHeader(formatter-\u003eformat(key), value);\n126:   } else {\n127:     encodeHeader(key, value);\n128:   }\n129: }\n130: \n131: void ResponseEncoderImpl::encode1xxHeaders(const ResponseHeaderMap\u0026 headers) {\n132:   ASSERT(HeaderUtility::isSpecial1xx(headers));\n133:   encodeHeaders(headers, false);\n134:   // Don't consider 100-continue responses as the actual response.\n135:   started_response_ = false;\n136: }\n137: \n138: void StreamEncoderImpl::encodeHeadersBase(const RequestOrResponseHeaderMap\u0026 headers,\n139:                                           absl::optional\u003cuint64_t\u003e status, bool end_stream,\n140:                         