114: void StreamEncoderImpl::encodeHeader(absl::string_view key, absl::string_view value) {
115:   ASSERT(!key.empty());
116: 
117:   const uint64_t header_size = connection_.buffer().addFragments({key, COLON_SPACE, value, CRLF});
