138: void StreamEncoderImpl::encodeHeadersBase(const RequestOrResponseHeaderMap& headers,
139:                                           absl::optional<uint64_t> status, bool end_stream,
140:                                           bool bodiless_request) {
141:   HeaderKeyFormatterOptConstRef formatter(headers.formatter());
142:   if (!formatter.has_value()) {
143:     formatter = connection_.formatter();
144:   }
145: 
146:   const Http::HeaderValues& header_values = Http::Headers::get();
147:   bool saw_content_length = false;
148:   headers.iterate(
149:       [this, &header_values, formatter](const HeaderEntry& header) -> HeaderMap::Iterate {
150:         absl::string_view key_to_use = header.key().getStringView();
151:         uint32_t key_size_to_use = header.key().size();
152:         // Translate :authority -> host so that upper layers do not need to deal with this.
153:         if (key_size_to_use > 1 && key_to_use[0] == ':' && key_to_use[1] == 'a') {
154:           key_to_use = absl::string_view(header_values.HostLegacy.get());
155:           key_size_to_use = header_values.HostLegacy.get().size();
156:         }
157: 
158:         // Skip all headers starting with ':' that make it here.
159:         if (key_to_use[0] == ':') {
160:           return HeaderMap::Iterate::Continue;
161:         }
162: 
163:         encodeFormattedHeader(key_to_use, header.value().getStringView(), formatter);
164: 
165:         return HeaderMap::Iterate::Continue;
166:       });
167: 
168:   if (headers.ContentLength()) {
169:     saw_content_length = true;
170:   }
171: 
172:   ASSERT(!headers.TransferEncoding());
173: 
174:   // Assume we are chunk encoding unless we are passed a content length or this is a header only
175:   // response. Upper layers generally should strip transfer-encoding since it only applies to
176:   // HTTP/1.1. The codec will infer it based on the type of response.
177:   // for streaming (e.g. SSE stream sent to hystrix dashboard), we do not want
178:   // chunk transfer encoding but we don't have a content-length so disable_chunk_encoding_ is
179:   // consulted before enabling chunk encoding.
180:   //
181:   // Note that for HEAD requests Envoy does best-effort guessing when there is no
182:   // content-length. If a client makes a HEAD request for an upstream resource
183:   // with no bytes but the upstream response doesn't include "Content-length: 0",
184:   // Envoy will incorrectly assume a subsequent response to GET will be chunk encoded.
185:   if (saw_content_length || disable_chunk_encoding_) {
186:     chunk_encoding_ = false;
187:   } else {
188:     if (status && (*status < 200 || *status == 204)) {
189:       // For 1xx and 204 responses, do not send the chunked encoding header or enable chunked
190:       // encoding: https://tools.ietf.org/html/rfc7230#section-3.3.1
191:       chunk_encoding_ = false;
192:     } else if (status && *status == 304) {
193:       // For 304 response, since it should never have a body, we should not need to chunk_encode at
194:       // all.
195:       chunk_encoding_ = false;
196:     } else if (end_stream && !is_response_to_head_request_) {
197:       // If this is a headers-only stream, append an explicit "Content-Length: 0" unless it's a
198:       // response to a HEAD request.
199:       // For 204s and 1xx where content length is disallowed, don't append the content length but
200:       // also don't chunk encode.
201:       // Also do not add content length for requests which should not have a
202:       // body, per https://tools.ietf.org/html/rfc7230#section-3.3.2
203:       if (!status || (*status >= 200 && *status != 204)) {
204:         if (!bodiless_request) {
205:           encodeFormattedHeader(header_values.ContentLength.get(), "0", formatter);
206:         }
207:       }
208:       chunk_encoding_ = false;
209:     } else if (connection_.protocol() == Protocol::Http10) {
210:       chunk_encoding_ = false;
211:     } else {
212:       // For responses to connect requests, do not send the chunked encoding header:
213:       // https://tools.ietf.org/html/rfc7231#section-4.3.6.
214:       if (!is_response_to_connect_request_) {
215:         encodeFormattedHeader(header_values.TransferEncoding.get(),
216:                               header_values.TransferEncodingValues.Chunked, formatter);
217:       }
218:       // We do not apply chunk encoding for HTTP upgrades, including CONNECT style upgrades.
219:       // If there is a body in a response on the upgrade path, the chunks will be
220:       // passed through via maybeDirectDispatch so we need to avoid appending
221:       // extra chunk boundaries.
222:       //
223:       // When sending a response to a HEAD request Envoy may send an informational
224:       // "Transfer-Encoding: chunked" header, but should not send a chunk encoded body.
225:       chunk_encoding_ = !Utility::isUpgrade(headers) && !is_response_to_head_request_ &&
226:                         !is_response_to_connect_request_;
227:     }
228:   }
229: 
230:   connection_.buffer().add(CRLF);
231: 
232:   if (end_stream) {
233:     endEncode();
234:   } else {
235:     flushOutput();
236:   }
237: }
