239: void StreamEncoderImpl::encodeData(Buffer::Instance& data, bool end_stream) {
240:   // end_stream may be indicated with a zero length data buffer. If that is the case, so not
241:   // actually write the zero length buffer out.
242:   if (data.length() > 0) {
243:     if (chunk_encoding_) {
244:       std::string chunk_header = absl::StrCat(absl::Hex(data.length()), CRLF);
245:       connection_.buffer().add(std::move(chunk_header));
246:     }
247: 
248:     connection_.buffer().move(data);
249: 
250:     if (chunk_encoding_) {
251:       connection_.buffer().add(CRLF);
252:     }
253:   }
254: 
255:   if (end_stream) {
256:     endEncode();
257:   } else {
258:     flushOutput();
259:   }
260: }
