267: void StreamEncoderImpl::encodeTrailersBase(const HeaderMap& trailers) {
268:   if (!connection_.enableTrailers()) {
269:     return endEncode();
270:   }
271:   // Trailers only matter if it is a chunk transfer encoding
272:   // https://tools.ietf.org/html/rfc7230#section-4.4
273:   if (chunk_encoding_) {
274:     // Finalize the body
275:     connection_.buffer().add(LAST_CHUNK);
276: 
277:     // TODO(mattklein123): Wire up the formatter if someone actually asks for this (very unlikely).
278:     trailers.iterate([this](const HeaderEntry& header) -> HeaderMap::Iterate {
279:       encodeFormattedHeader(header.key().getStringView(), header.value().getStringView(),
280:                             HeaderKeyFormatterOptConstRef());
281:       return HeaderMap::Iterate::Continue;
282:     });
283: 
284:     connection_.buffer().add(CRLF);
285:   }
286: 
287:   flushOutput();
288:   notifyEncodeComplete();
289: }
