318: void ServerConnectionImpl::maybeAddSentinelBufferFragment(Buffer::Instance& output_buffer) {
319:   // It's messy and complicated to try to tag the final write of an HTTP response for response
320:   // tracking for flood protection. Instead, write an empty buffer fragment after the response,
321:   // to allow for tracking.
322:   // When the response is written out, the fragment will be deleted and the counter will be updated
323:   // by ServerConnectionImpl::releaseOutboundResponse()
324:   auto fragment =
325:       Buffer::OwnedBufferFragmentImpl::create(absl::string_view("", 0), response_buffer_releasor_);
326:   output_buffer.addBufferFragment(*fragment.release());
327:   ASSERT(outbound_responses_ < kMaxOutboundResponses);
328:   outbound_responses_++;
329: }
