402: void ResponseEncoderImpl::encodeHeaders(const ResponseHeaderMap& headers, bool end_stream) {
403:   started_response_ = true;
404: 
405:   // The contract is that client codecs must ensure that :status is present and valid.
406:   ASSERT(headers.Status() != nullptr);
407:   uint64_t numeric_status = Utility::getResponseStatus(headers);
408: 
409:   absl::string_view response_prefix;
410:   if (connection_.protocol() == Protocol::Http10 && connection_.supportsHttp10()) {
411:     response_prefix = HTTP_10_RESPONSE_PREFIX;
412:   } else {
413:     response_prefix = RESPONSE_PREFIX;
414:   }
415: 
416:   StatefulHeaderKeyFormatterOptConstRef formatter(headers.formatter());
417: 
418:   absl::string_view reason_phrase;
419:   if (formatter.has_value() && !formatter->getReasonPhrase().empty()) {
420:     reason_phrase = formatter->getReasonPhrase();
421:   } else {
422:     const char* status_string = CodeUtility::toString(static_cast<Code>(numeric_status));
423:     uint32_t status_string_len = strlen(status_string);
424:     reason_phrase = {status_string, status_string_len};
425:   }
426: 
427:   connection_.buffer().addFragments(
428:       {response_prefix, absl::StrCat(numeric_status), SPACE, reason_phrase, CRLF});
429: 
430:   if (numeric_status >= 300) {
431:     // Don't do special CONNECT logic if the CONNECT was rejected.
432:     is_response_to_connect_request_ = false;
433:   }
434: 
435:   encodeHeadersBase(headers, absl::make_optional<uint64_t>(numeric_status), end_stream, false);
436: }
