282:   // downstream codecs decode.
283:   RETURN_IF_ERROR(HeaderUtility::checkRequiredRequestHeaders(headers));
284:   // Verify that a filter hasn't added an invalid header key or value.
285:   RETURN_IF_ERROR(HeaderUtility::checkValidRequestHeaders(headers));
