287:   // This must exist outside of the scope of isUpgrade as the underlying memory is
288:   // needed until encodeHeadersBase has been called.
289:   Http::RequestHeaderMapPtr modified_headers;
290:   if (Http::Utility::isUpgrade(headers)) {
291:     modified_headers = createHeaderMap<RequestHeaderMapImpl>(headers);
292:     upgrade_type_ = std::string(headers.getUpgradeValue());
293:     Http::Utility::transformUpgradeRequestFromH1toH2(*modified_headers);
294:     encodeHeadersBase(*modified_headers, end_stream);
295:   } else if (headers.Method() && headers.Method()->value() == "CONNECT") {
296:     modified_headers = createHeaderMap<RequestHeaderMapImpl>(headers);
297:     modified_headers->removeScheme();
298:     modified_headers->removePath();
299:     modified_headers->removeProtocol();
