333: void ConnectionImpl::StreamImpl::encodeTrailersBase(const HeaderMap& trailers) {
334:   parent_.updateActiveStreamsOnEncode(*this);
335:   ASSERT(!local_end_stream_);
336:   local_end_stream_ = true;
337:   if (pending_send_data_->length() > 0) {
338:     // In this case we want trailers to come after we release all pending body data that is
339:     // waiting on window updates. We need to save the trailers so that we can emit them later.
340:     // However, for empty trailers, we don't need to to save the trailers.
341:     ASSERT(!pending_trailers_to_encode_);
342:     const bool skip_encoding_empty_trailers = trailers.empty();
343:     if (!skip_encoding_empty_trailers) {
344:       pending_trailers_to_encode_ = cloneTrailers(trailers);
345:       onLocalEndStream();
346:     }
347:   } else {
348:     submitTrailers(trailers);
349:     if (parent_.sendPendingFramesAndHandleError()) {
350:       // Intended to check through coverage that this error case is tested
351:       return;
352:     }
353:   }
354: }
