362:     parent_.adapter_->SubmitMetadata(stream_id_, 16 * 1024, std::move(source));
363:   }
364: 
365:   if (parent_.sendPendingFramesAndHandleError()) {
366:     // Intended to check through coverage that this error case is tested
367:     return;
368:   }
